INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, 'cee34a01-cf1d-4a36-8c58-9f3bc9960035'::uuid, 2023, 'Paper-I', 'Which of the following Articles of the Indian Constitution provides for ''protection of monuments and places and objects of national importance''?', 'Article 35', 'Article 39', 'Article 45', 'Article 49', 4, 'Article 49 of the Indian Constitution provides for the protection of monuments, places, and objects of national importance.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, 'cee34a01-cf1d-4a36-8c58-9f3bc9960035'::uuid, 2023, 'Paper-I', 'Article 29 of the Indian Constitution provides for which of the following?', 'Protection in respect of conviction for offences', 'Protection of interests of minorities', 'Right against discrimination', 'Protection of certain rights regarding freedom of speech', 2, 'Article 29 protects the interests of minorities, including the right to conserve their language, script, and culture.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, 'cee34a01-cf1d-4a36-8c58-9f3bc9960035'::uuid, 2023, 'Paper-I', 'Which of the following pairs of ''Article – provision'' is/are correctly matched as per the context of the Indian Constitution? I. Article 5 - Citizenship at the commencement of the Constitution. II. Article 10 - Rights of citizenship of certain persons of Indian origin residing outside India.', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 1, 'Article 5 deals with citizenship at the commencement of the Constitution (correct). Article 10 deals with continuance of citizenship, not persons residing outside India (Article 8 deals with that). So Only I is correct.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, 'cee34a01-cf1d-4a36-8c58-9f3bc9960035'::uuid, 2023, 'Paper-I', 'As of August 2023, which of the following states in India does NOT have a bicameral legislature?', 'Karnataka', 'Andhra Pradesh', 'Bihar', 'West Bengal', 4, 'West Bengal has a unicameral legislature (only Legislative Assembly). Karnataka, Andhra Pradesh, and Bihar have bicameral legislatures.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, 'cee34a01-cf1d-4a36-8c58-9f3bc9960035'::uuid, 2023, 'Paper-I', 'In India, the Governor of a State is appointed by the ______.', 'Prime Minister', 'President', 'Council of Ministers', 'Vice President', 2, 'The Governor of a State is appointed by the President of India under Article 155 of the Constitution.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, 'cee34a01-cf1d-4a36-8c58-9f3bc9960035'::uuid, 2023, 'Paper-I', 'The ______ acts as the ex-officio Chairman of the Rajya Sabha.', 'President', 'Vice President', 'Prime Minister', 'Comptroller and Auditor General', 2, 'The Vice President of India is the ex-officio Chairman of the Rajya Sabha, as per Article 64 of the Constitution.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, 'cee34a01-cf1d-4a36-8c58-9f3bc9960035'::uuid, 2023, 'Paper-I', 'If the court finds that a person is holding office but is not entitled to hold that office, it issues the writ of ______.', 'quo warranto', 'habeas corpus', 'mandamus', 'certiorari', 1, 'The writ of quo warranto (''by what authority'') is used to question the legality of a person holding a public office.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, 'cee34a01-cf1d-4a36-8c58-9f3bc9960035'::uuid, 2023, 'Paper-I', 'Which of the following states have more than 30 Lok Sabha constituencies? I. West Bengal II. Madhya Pradesh', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 1, 'West Bengal has 42 Lok Sabha constituencies (more than 30). Madhya Pradesh has 29 (less than 30). So Only I is correct.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, 'cee34a01-cf1d-4a36-8c58-9f3bc9960035'::uuid, 2023, 'Paper-I', 'Which of the following subjects is included in the Union list in the Indian Constitution? I. Forests II. Defence', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 2, 'Defence is included in the Union List (List I). Forests are in the Concurrent List (List III). So Only II is correct.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, 'cee34a01-cf1d-4a36-8c58-9f3bc9960035'::uuid, 2023, 'Paper-I', 'Which of the following statements is/are correct regarding the powers of the Lok Sabha? I. It can Introduce and enact money and non-money bills. II. It can give the Union parliament power to make laws on matters included in the State list.', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 1, 'Lok Sabha can introduce and enact all types of bills (Statement I correct). Statement II is incorrect; only Rajya Sabha can, with special majority, empower Parliament to make laws on State List subjects under Article 249.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, 'cee34a01-cf1d-4a36-8c58-9f3bc9960035'::uuid, 2023, 'Paper-I', 'Which Schedule of the Indian Constitution is related to ''powers, authority and responsibilities of Panchayats''?', 'Ninth', 'Tenth', 'Eleventh', 'Twelfth', 3, 'The Eleventh Schedule (Article 243G) lists the powers, authority, and responsibilities of Panchayats in India.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, 'cee34a01-cf1d-4a36-8c58-9f3bc9960035'::uuid, 2023, 'Paper-I', 'The Constitutional amendments assigned ______ subjects to the local governments.', '16', '19', '24', '29', 4, 'The 73rd and 74th Constitutional Amendments assigned 29 subjects to the local governments (Panchayats - 29 subjects in 11th Schedule).', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, 'cee34a01-cf1d-4a36-8c58-9f3bc9960035'::uuid, 2023, 'Paper-I', 'Which of the following constitutional amendments is about rural local governments?', '72nd Amendment', '73rd Amendment', '74th Amendment', '75th Amendment', 2, 'The 73rd Constitutional Amendment Act, 1992, provides for Panchayati Raj institutions (rural local governments).', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, 'cee34a01-cf1d-4a36-8c58-9f3bc9960035'::uuid, 2023, 'Paper-I', 'Which Article of the Indian Constitution is related to ''powers, authority and responsibilities of Municipalities, etc.''?', 'Article 243C', 'Article 243G', 'Article 243S', 'Article 243W', 4, 'Article 243W deals with the powers, authority, and responsibilities of Municipalities under the 74th Amendment.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, 'cee34a01-cf1d-4a36-8c58-9f3bc9960035'::uuid, 2023, 'Paper-I', 'Which of the following statements is/are correct regarding local government? I. Local government is government at the village and district level. II. It is convenient for the people to approach the local government for solving their problems both quickly and with minimum cost.', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 3, 'Both statements are correct: local government operates at village and district levels, and provides quick, cost-effective solutions to local problems.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '13bcf297-a2d4-4044-adfe-c24a66531e41'::uuid, 2023, 'Paper-I', 'Tantia Tope was killed in ______.', '1857', '1858', '1859', '1860', 3, 'Tantia Tope (Ramachandra Pandurang Tope), a key leader of the 1857 revolt, was executed on 18 April 1859.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '13bcf297-a2d4-4044-adfe-c24a66531e41'::uuid, 2023, 'Paper-I', 'Who was the Nawab of Bengal during the Battle of Plassey?', 'Murshid Quli Khan', 'Alivardi Khan', 'Mir Qasim', 'Sirajuddaulah', 4, 'Sirajuddaulah was the Nawab of Bengal during the Battle of Plassey (1757), which was fought against the British East India Company.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '13bcf297-a2d4-4044-adfe-c24a66531e41'::uuid, 2023, 'Paper-I', 'The Vernacular Press Act was enacted in ______.', '1876', '1877', '1878', '1879', 3, 'The Vernacular Press Act was enacted in 1878 by Lord Lytton to restrict the freedom of the Indian-language press.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '13bcf297-a2d4-4044-adfe-c24a66531e41'::uuid, 2023, 'Paper-I', 'Which of the following statements is/are correct regarding the origins of the Indian National Congress? I. It was established on 28th December 1885. II. Allan Octavian Hume played a key role in its establishment.', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 3, 'Both statements are correct: INC was founded on December 28, 1885, and A.O. Hume played a key role in its formation.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '13bcf297-a2d4-4044-adfe-c24a66531e41'::uuid, 2023, 'Paper-I', 'Which of the following pairs of ''organisation - year of formation'' is/are correctly matched? I. Indian Industrial and Commercial Congress - 1917 II. Federation of the Indian Chamber of Commerce and Industries - 1927', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 3, 'Both are correct: Indian Industrial and Commercial Congress was established in 1917, and FICCI was established in 1927.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '13bcf297-a2d4-4044-adfe-c24a66531e41'::uuid, 2023, 'Paper-I', 'Which of the following statements is/are correct regarding the Brahmo Samaj? I. It prohibited all forms of idolatry and sacrifice. II. It forbade its members from criticising other religious practices.', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 1, 'Brahmo Samaj prohibited idolatry and sacrifices (Statement I correct). It did not forbid criticism of other religious practices (Statement II incorrect). So Only I is correct.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '13bcf297-a2d4-4044-adfe-c24a66531e41'::uuid, 2023, 'Paper-I', 'Who established the Indian Statistical Institute (ISI) in Calcutta?', 'M.S. Swaminathan', 'P.C. Mahalanobis', 'C.R. Rao', 'D.R. Kaprekar', 2, 'P.C. Mahalanobis established the Indian Statistical Institute (ISI) in Calcutta (Kolkata) in 1931.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '13bcf297-a2d4-4044-adfe-c24a66531e41'::uuid, 2023, 'Paper-I', 'The Tata Iron and Steel Company (TISCO) was incorporated in ______.', '1901', '1903', '1905', '1907', 4, 'TISCO (now Tata Steel) was incorporated in 1907 by Jamsetji Tata and was established at Jamshedpur.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '3e74357f-d7ad-4652-8435-eaa0f7cdfef6'::uuid, 2023, 'Paper-I', 'Hill Area Development Programmes were initiated during ______.', 'First Five Year Plan', 'Third Five Year Plan', 'Fourth Five Year Plan', 'Fifth Five Year Plan', 3, 'Hill Area Development Programmes were initiated during the Fourth Five Year Plan (1969-74) to address the developmental needs of hilly regions.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '3e74357f-d7ad-4652-8435-eaa0f7cdfef6'::uuid, 2023, 'Paper-I', 'Which of the following statements is/are correct in the context of the Green Revolution in India? I. This refers to the large increase in production of foodgrains resulting from the use of high yielding variety (HYV) seeds. II. The use of these seeds required the use of fertilisers and pesticide in the correct quantities as well as regular supply of water.', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 3, 'Both statements are correct: Green Revolution involved HYV seeds, and their success required fertilizers, pesticides, and adequate water supply.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '3e74357f-d7ad-4652-8435-eaa0f7cdfef6'::uuid, 2023, 'Paper-I', 'Which of the following statements is/are correct in the context of a capitalist society? I. Only those consumer goods are produced that are in demand. II. The goods produced are distributed among people on the basis of Purchasing Power.', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 3, 'Both statements are correct: capitalism produces goods based on demand, and distribution is based on purchasing power (ability to pay).', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '3e74357f-d7ad-4652-8435-eaa0f7cdfef6'::uuid, 2023, 'Paper-I', 'Government bonds are issued with original maturity of ______.', 'less than 120 days', '90 days or more', 'one year or more', 'less than one year', 3, 'Government bonds are long-term debt instruments with original maturity of one year or more (up to 30 years or more).', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '3e74357f-d7ad-4652-8435-eaa0f7cdfef6'::uuid, 2023, 'Paper-I', 'Price elasticity of demand for a good can be expressed as ______.', 'percentage change in income / percentage change in price', 'net change in price / percentage change in demand', 'percentage change in demand / percentage change in price', 'net change in quantity / percentage change in supply', 3, 'Price elasticity of demand = (% change in quantity demanded) / (% change in price).', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '3e74357f-d7ad-4652-8435-eaa0f7cdfef6'::uuid, 2023, 'Paper-I', 'The speculative demand for money can be written as (where r is the market rate of interest and rmax and rmin are the upper and lower limits of r)', '(rmax + r)/(r - rmin)', '(rmax - r)/(r - rmin)', '(rmax - r)/(r + rmin)', '(rmax + r)/(r + rmin)', 2, 'Speculative demand for money = (rmax - r)/(r - rmin), representing the Keynesian liquidity preference theory.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '3e74357f-d7ad-4652-8435-eaa0f7cdfef6'::uuid, 2023, 'Paper-I', 'The concept of human development was introduced by ______.', 'Amartya Sen', 'Mahbub ul Haq', 'Jean Drèze', 'Martha Nussbaum', 2, 'Mahbub ul Haq introduced the concept of Human Development (UNDP) and the Human Development Index, drawing on Amartya Sen''s work on capabilities.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, 'e587b482-1005-40dc-b6dd-3d9c2119a753'::uuid, 2023, 'Paper-I', 'The National Highways constitute about ______ percent of the total road length in India?', '2', '4', '12', '18', 1, 'National Highways constitute about 2% of the total road length in India but carry about 40% of the traffic.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '3e74357f-d7ad-4652-8435-eaa0f7cdfef6'::uuid, 2023, 'Paper-I', 'Which of the following statements is/are correct regarding the National Bank for Agriculture and Rural Development (NABARD)? I. NABARD was set up in 1972. II. NABARD was set up as an apex body to coordinate the activities of all institutions involved in the rural financing system.', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 2, 'NABARD was set up in 1982 (not 1972). It is an apex body for rural financing coordination. So Only II is correct.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, 'fece8020-1cd0-4cd3-ab7d-23d1da0243f9'::uuid, 2023, 'Paper-I', 'As of July 2023, there are ________ districts in Telangana.', '28', '33', '36', '39', 2, 'As of July 2023, Telangana has 33 districts after the recent reorganization of districts in 2016 and further additions.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, 'fece8020-1cd0-4cd3-ab7d-23d1da0243f9'::uuid, 2023, 'Paper-I', 'Annual Normal Rainfall in Telangana is ________ millimetres (mm).', '805.4', '875.4', '905.4', '975.4', 3, 'The annual normal rainfall in Telangana is approximately 905.4 mm, received mostly during the southwest monsoon.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, 'fece8020-1cd0-4cd3-ab7d-23d1da0243f9'::uuid, 2023, 'Paper-I', 'Telangana is endowed with a rich diversity of flora and fauna with _____ mammal species.', '21', '28', '103', '365', 2, 'Telangana has about 28 mammal species as per various biodiversity assessments.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, 'c14a6349-1631-4eb0-8302-f2c798195166'::uuid, 2023, 'Paper-I', 'Which of the following pairs of ''wildlife sanctuary – district'' is/are correctly matched? I. Manjira Wild Life Sanctuary - Sangareddy II. Kinnerasani Wild Life Sanctuary - Medak', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 1, 'Manjira Wildlife Sanctuary is in Sangareddy district (correct). Kinnerasani Wildlife Sanctuary is in Khammam district, not Medak. So Only I is correct.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, 'fece8020-1cd0-4cd3-ab7d-23d1da0243f9'::uuid, 2023, 'Paper-I', 'Which of the following statements is/are correct regarding Telangana state statistics as per Census 2011? I. Total number of Municipal Corporations is 129. II. Total number of Gram Panchayats is 12769.', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 2, 'As per Census 2011, Telangana has 12769 Gram Panchayats (Statement II correct). The number of Municipal Corporations is less than 129. So Only II is correct.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, 'fece8020-1cd0-4cd3-ab7d-23d1da0243f9'::uuid, 2023, 'Paper-I', 'As per Census 2011, rural population of Telangana is _____ percent of the total population of the state.', '38.88', '36.12', '61.12', '63.88', 1, 'As per Census 2011, Telangana''s rural population was 38.88% of the total population.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, 'fece8020-1cd0-4cd3-ab7d-23d1da0243f9'::uuid, 2023, 'Paper-I', 'Which of the following statements is/are correct regarding Telangana state statistics as per Census 2011? I. Total number of inhabited villages is 9834. II. Total number of un-inhabited villages is 379.', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 3, 'Both statements are correct: Telangana has 9834 inhabited villages and 379 uninhabited villages as per Census 2011.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, 'fece8020-1cd0-4cd3-ab7d-23d1da0243f9'::uuid, 2023, 'Paper-I', 'Telangana registered ______ percent growth rate in production of Foodgrains between 2019-20 and 2020-21.', '8.6', '14.6', '19.6', '22.6', 3, 'Telangana registered 19.6% growth in foodgrains production between 2019-20 and 2020-21, according to government data.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '63f54208-07b4-4014-b501-f8691de5e2c1'::uuid, 2023, 'Paper-I', 'In the Export Preparedness Index 2021, Telangana has scored ______ in the Business environment indicator.', '85', '90', '95', '100', 2, 'Telangana scored 90 in the Business environment indicator of the Export Preparedness Index 2021.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, 'fece8020-1cd0-4cd3-ab7d-23d1da0243f9'::uuid, 2023, 'Paper-I', 'Which of the following statements is/are correct regarding the Road Transportation network in Telangana? I. 61.80 percent of the total road length in Telangana are rural roads. II. 9.56 percent of the total road length in Telangana are National Highways.', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 1, '61.80% of Telangana''s road length is rural roads (Statement I correct). National Highways constitute only about 2.8% (not 9.56%). So Only I is correct.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, 'c14a6349-1631-4eb0-8302-f2c798195166'::uuid, 2023, 'Paper-I', 'Raja Rajeswara (Rajanna) Temple is situated in ______ town of Telangana.', 'Vemulawada', 'Alampur', 'Bhadrachalam', 'Basara', 1, 'Raja Rajeswara (Rajanna) Temple is located in Vemulawada, Karimnagar district, dedicated to Lord Shiva.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, 'c14a6349-1631-4eb0-8302-f2c798195166'::uuid, 2023, 'Paper-I', 'Bathukamma is a festival of _____. This festival is treated as a symbol of Telangana''s cultural identity.', 'bulls', 'flowers', 'trumpets', 'elephants', 2, 'Bathukamma is a floral festival celebrated in Telangana, where women arrange flowers in a conical shape and worship the goddess Gauri.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, 'c14a6349-1631-4eb0-8302-f2c798195166'::uuid, 2023, 'Paper-I', 'The narratives of which of the following art forms describe struggles against exploitation?', 'Golla Suddulu', 'Oggu Kathalu', 'Gotralu', 'Dhoom Dham', 2, 'Oggu Kathalu are folk narratives that describe struggles against exploitation, performed by the Oggu community in Telangana.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, 'c14a6349-1631-4eb0-8302-f2c798195166'::uuid, 2023, 'Paper-I', 'Which of the following statements is/are correct in the context of the State symbols of Telangana? I. Tangedu flower is used during the Batukamma festival by women folk. II. Lord Rama worshipped Jammi Chettu before invading Lanka and vanquished Ravana.', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 3, 'Both statements are correct: Tangedu flowers are used in Bathukamma, and Lord Rama worshipped Jammi Chettu (Prosopis cineraria) before the Lanka invasion.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, 'c14a6349-1631-4eb0-8302-f2c798195166'::uuid, 2023, 'Paper-I', 'Which of the following statements is/are correct regarding the Banjara Needle Crafts? I. Banjara Needle Crafts are the traditional handmade fabrics made by Banjaras (the tribal Gypsies) in Telangana. II. It is a form of embroidery and mirror work on fabrics employing the needlecraft.', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 3, 'Both statements are correct: Banjara needle crafts are traditional handmade fabrics by Banjaras, involving embroidery and mirror work.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, 'c14a6349-1631-4eb0-8302-f2c798195166'::uuid, 2023, 'Paper-I', 'Which of the following statements is/are correct regarding Medak Cathedral? I. It was built by Charles Walker Fasnet. II. It was consecrated on 25 December 1904.', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 3, 'Both statements are correct: Medak Cathedral was built by Charles Walker Fasnet and consecrated on December 25, 1904.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '63f54208-07b4-4014-b501-f8691de5e2c1'::uuid, 2023, 'Paper-I', 'Which of the following statements is/are correct regarding the Mana Ooru-Mana Badi Programme? I. Telangana State Government started the programme for comprehensive development and strengthening of Infrastructure facilities in 26,065 Schools in 3 phases spread over 3 years. II. The programme was started with total budget outlay of Rs.17289 crores.', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 3, 'Both statements are correct: the programme covers 26,065 schools over 3 phases with a total budget of ₹17,289 crores.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '385bbfda-8fa8-4d58-98a8-7b26d3a3c13b'::uuid, 2023, 'Paper-I', 'On 17 September 1948, the Indian government conducted a military operation called ______ to bring Hyderabad state into the Indian Union.', 'Operation Trident', 'Operation Vijay', 'Operation Python', 'Operation Polo', 4, 'Operation Polo was the police action conducted by the Indian government on 17 September 1948 to annex Hyderabad into the Indian Union.', 'medium');
